function canvasDataUrl(c,quality=.88){return c.toDataURL('image/webp',quality)}
async function runPool(tasks,workers,fn,onProgress){let next=0,done=0;await Promise.all(workers.map(async worker=>{while(true){const i=next++;if(i>=tasks.length)return;await fn(tasks[i],worker,i);done++;onProgress?.(done,tasks.length)}}))}
function renderPreview(it){if(crops.children.length>=80&&it.detectionStatus!=='need_review')return;const box=document.createElement('div'),img=new Image(),meta=document.createElement('div');box.className='box '+(it.pass?'pass':'fail')+(it.detectionStatus==='need_review'?' review':'');img.src=it.dataUrl;meta.className='meta';meta.innerHTML=`<span class="tag ${it.pass?'green':'redtag'}">${it.pass?'GRID PASS':'GRID FAIL'}</span><span class="tag ${it.detectionStatus==='auto_ok'?'green':'orange'}">${it.detectionStatus==='auto_ok'?'AUTO OK':'ต้องตรวจ'}</span><span class="tag blue">${it.cardId}</span><span class="tag graytag">${it.ocr.method}</span><div class="ocr"><b>ผลไทย:</b> ${it.detectedFunctionLabel||'-'}</div><div class="ocr"><b>OCR รอบแรก:</b> ${it.ocr.first?.raw||'-'}</div>${it.ocr.second?`<div class="ocr"><b>OCR รอบสอง PSM ${it.ocr.second.psm} (${it.ocr.rescueSource||'fallback'}):</b> ${it.ocr.second.raw||'-'}</div>`:''}${it.ocr.top?`<div class="ocr"><b>ตัวเลขบรรทัดบน:</b> ${it.ocr.top.raw||'-'}</div>`:''}${it.ocr.completion?`<div class="ocr"><b>จับคู่เงื่อนไข:</b> ${it.ocr.completion.method} • ${it.ocr.lineCount||0} บรรทัด</div>`:''}`;box.append(img,meta);crops.appendChild(box)}
function reportObject(timing,counts){return{version:'promo-fast-accurate-v2.3-card-hint',created_at:new Date().toISOString(),source_file:sourceFile?{name:sourceFile.name,size:sourceFile.size,last_modified:sourceFile.lastModified}:null,pages:pdf?.numPages||0,class_counts:counts,total:items.length,grid_pass:items.filter(x=>x.pass).length,grid_fail:items.filter(x=>!x.pass).length,auto_ok:items.filter(x=>x.detectionStatus==='auto_ok').length,need_review:items.filter(x=>x.detectionStatus==='need_review').length,ready_to_upload:items.filter(x=>x.uploadable).length,ocr_calls:items.reduce((s,x)=>s+x.ocr.calls,0),badge_cards:items.filter(x=>x.ocr.method==='badge').length,general_cards:items.filter(x=>x.ocr.method==='general').length,card_hint_completions:items.filter(x=>x.ocr.completion).length,timing_ms:timing,cards:items.map(x=>({card_id:x.cardId,class_id:x.cls,page_no:x.page,card_no:x.no,grid_pass:x.pass,benefit_box:x.benefitBox,detection_status:x.detectionStatus,detected_function_label:x.detectedFunctionLabel,confidence:x.ocr.selected?.confidence||0,ocr_calls:x.ocr.calls,ocr_method:x.ocr.method,ocr_first:x.ocr.first?.raw||'',ocr_second:x.ocr.second?.raw||'',ocr_top:x.ocr.top?.raw||'',fallback_psm:x.ocr.second?.psm||null,rescue_source:x.ocr.rescueSource||'',promo_line_count:x.ocr.lineCount||0,completion_method:x.ocr.completion?.method||'',completion_missing_hints:x.ocr.completion?.missingHints||[]}))}}